// Quantum Daily P&L Report v1
// Pulls Alpaca positions, orders, account data and formats a clean report.

const ALPACA_KEY    = 'REDACTED_ALPACA_KEY_ID';
const ALPACA_SECRET = 'REDACTED_ALPACA_SECRET';
const ALPACA_BASE   = 'https://paper-api.alpaca.markets';
const NL = String.fromCharCode(10);

async function alpaca(path) {
  try {
    return await this.helpers.httpRequest({
      method: 'GET',
      url: ALPACA_BASE + path,
      headers: {
        'APCA-API-KEY-ID': ALPACA_KEY,
        'APCA-API-SECRET-KEY': ALPACA_SECRET,
      },
      json: true,
    });
  } catch (err) {
    console.log('[P&L] API error on ' + path + ': ' + (err.message || err));
    return null;
  }
}

// ─── FETCH DATA ───
const account    = await alpaca('/v2/account');
const positions  = await alpaca('/v2/positions') || [];
const todayISO   = new Date().toISOString().split('T')[0] + 'T00:00:00Z';
const allOrders  = await alpaca('/v2/orders?status=all&limit=200&after=' + todayISO) || [];

if (!account) {
  return [{ json: { message: '<b>Quantum Daily P&amp;L Report</b>' + NL + NL + 'Error: Could not connect to Alpaca.' } }];
}

// ─── ACCOUNT P&L ───
const equity     = parseFloat(account.equity) || 0;
const lastEquity = parseFloat(account.last_equity) || 0;
const totalPnL   = equity - lastEquity;
const totalPnLPct = lastEquity > 0 ? (totalPnL / lastEquity * 100) : 0;

// ─── UNREALIZED P&L from positions ───
let unrealizedPnL = 0;
const posData = [];
for (const p of positions) {
  const upl = parseFloat(p.unrealized_pl) || 0;
  const uplPct = (parseFloat(p.unrealized_plpc) || 0) * 100;
  unrealizedPnL += upl;
  posData.push({
    symbol: p.symbol,
    qty: parseInt(p.qty),
    side: p.side,
    upl: upl,
    uplPct: uplPct,
  });
}

// Realized = Total - Unrealized
const realizedPnL = totalPnL - unrealizedPnL;

// ─── TODAY'S SIGNALS (entry orders only) ───
// Count filled entry orders (market orders from brackets or simple)
const filledOrders = allOrders.filter(o => o.status === 'filled');
const entryOrders = filledOrders.filter(o =>
  o.type === 'market' && (o.order_class === 'bracket' || o.order_class === '' || !o.order_class)
);
const buySignals  = entryOrders.filter(o => o.side === 'buy');
const sellSignals = entryOrders.filter(o => o.side === 'sell');

// Deduplicate by symbol (count unique tickers)
const buyTickers  = [...new Set(buySignals.map(o => o.symbol))];
const sellTickers = [...new Set(sellSignals.map(o => o.symbol))];
const totalSignals = buyTickers.length + sellTickers.length;

// ─── TOP PERFORMERS ───
const sorted = [...posData].sort((a, b) => b.uplPct - a.uplPct);
const top3 = sorted.slice(0, 3).filter(p => p.uplPct !== 0);

// ─── STATUS ───
let status = 'Healthy';
let statusEmoji = '\u2705';
if (totalPnL < -500) { status = 'Under Pressure'; statusEmoji = '\u26A0\uFE0F'; }
if (totalPnL < -1000) { status = 'Risk Alert'; statusEmoji = '\uD83D\uDED1'; }

// ─── FORMAT DATE ───
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', {
  timeZone: 'America/New_York',
  month: 'long',
  day: 'numeric',
  year: 'numeric',
});

// ─── FORMAT P&L VALUES ───
function fmtPnL(val) {
  const sign = val >= 0 ? '+' : '';
  return sign + '$' + Math.abs(val).toFixed(2);
}

function fmtPct(val) {
  const sign = val >= 0 ? '+' : '';
  return sign + val.toFixed(1) + '%';
}

// ─── BUILD MESSAGE ───
let msg = '\uD83D\uDCCA <b>QUANTUM DAILY P&amp;L REPORT \u2014 ' + dateStr + '</b>' + NL + NL;

msg += 'Total Signals Today: ' + totalSignals + ' (' + buyTickers.length + ' BUY, ' + sellTickers.length + ' SELL)' + NL;
msg += 'Realized P&amp;L: ' + fmtPnL(realizedPnL) + NL;
msg += 'Unrealized P&amp;L: ' + fmtPnL(unrealizedPnL) + NL;
msg += 'Total P&amp;L: ' + fmtPnL(totalPnL) + ' (' + fmtPct(totalPnLPct) + ')' + NL + NL;

msg += 'Open Positions: ' + positions.length + NL;

if (top3.length > 0) {
  const topStr = top3.map(p => p.symbol + ' ' + fmtPct(p.uplPct)).join(', ');
  msg += 'Top Performers: ' + topStr + NL;
}

msg += 'Status: ' + status + ' ' + statusEmoji + NL + NL;

msg += 'Broad Scanner ran successfully. Position flips and brackets active.';

return [{ json: { message: msg } }];
